_TOAST_TYPE_MAP = {
    "hide": 0,
    "error": 1,
    "failed": 1,
    "fail": 1,
    "warning": 2,
    "warn": 2,
    "message": 3,
    "info": 3,
    "success": 4,
    "ok": 4,
}

_TOAST_POSITION_MAP = {
    "top": 0,
    "bottom": 1,
    "buttom": 1,
    "left": 2,
    "right": 3,
}


def _normalize_text_for_match(value, case_sensitive=False, ignore_accents=False):
    value = str(value)
    if ignore_accents:
        value = "".join(
            ch for ch in unicodedata.normalize("NFD", value)
            if unicodedata.category(ch) != "Mn"
        )
        value = value.replace("đ", "d").replace("Đ", "D")
    if not case_sensitive:
        value = value.lower()
    return value


class ToastProgress:
    def __init__(self, device, toast_id):
        self._device = device
        self.id = toast_id

    def updateMsg(self, message):
        return self._device._toast_progress_update(self.id, message)

    def update_msg(self, message):
        return self.updateMsg(message)

    def stop(self):
        return self._device._toast_progress_stop(self.id)


class zxtouch:
    def __init__(self, ip):
        self.s = socket.socket()
        self.s.connect((str(ip), 6000))
        time.sleep(0.1)

    def touch(self, type, finger_index, x, y):
        """Perform a touch event

        :param type: touch type
        :param finger_index: which finger you want to perform touch
        :param x: x coordinate
        :param y: y coordinate
        :return: None
        """
        if int(type) > 19:
            print("Touch index should not be greater than 19.")
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_PERFORM_TOUCH,
                                                   '1{}{:02d}{:05d}{:05d}'.format(type, finger_index, int(x * 10),
                                                                                  int(y * 10))))

    def touch_with_list(self, touch_list: list):
        """Perform touch events with a list of events
        touch list should be a list of dictionary that you want to perform touch with following format

        :param touch_list: [{"type": ?, "finger_index": ?, "x": ?, "y": ?}]
        :return: None
        """
        event_data = ''
        for touch_event in touch_list:
            event_data += '{}{:02d}{:05d}{:05d}'.format(touch_event['type'], touch_event['finger_index'],
                                                        touch_event['x'] * 10,
                                                        touch_event['y'] * 10)
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_PERFORM_TOUCH, str(len(touch_list)) + event_data))

    def switch_to_app(self, bundle_identifier):
        """Bring an application to foreground

        :param bundle_identifier: the bundle identifier of the application
        :return: Result tuple

        The format of the result tuple:
        result_tuple[0]: True if no error happens when executing the command on your device. False otherwise
        result_tuple[1]: error info if result_tuple[0] == False. Otherwise ""
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_PROCESS_BRING_FOREGROUND, bundle_identifier))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def close_app(self, bundle_identifier):
        """Close/terminate an app by bundle identifier."""
        return self._json_raw_task_request(tasktypes.TASK_PROCESS_CLOSE_APP, bundle_identifier, timeout=10)

    def show_alert_box(self, title, content, duration):
        """Show alert box on device

        Args:
            title: title of the alert box
            content: content of the alert box
            duration: the time the alert box shows before disappear

        Returns:
            Result tuple: (success?, error_message/return value)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_SHOW_ALERT_BOX, title, content, duration))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def run_shell_command(self, command):
        """Run shell command on device as root

        :param command: command to run
        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_RUN_SHELL, command))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def _crane_request(self, crane_task, *args):
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_CRANE, crane_task, *args))
        chunks = []
        old_timeout = self.s.gettimeout()
        self.s.settimeout(5)
        try:
            while True:
                chunk = self.s.recv(65535)
                chunks.append(chunk)
                if chunk.endswith(b"\r\n"):
                    break
        finally:
            self.s.settimeout(old_timeout)
        result = datahandler.decode_socket_data(b"".join(chunks))
        if not result[0]:
            return result
        payload = result[1][0] if len(result[1]) else "{}"
        try:
            decoded_payload = base64.b64decode(payload).decode()
            return True, json.loads(decoded_payload)
        except Exception:
            return False, "Unable to decode Crane response: " + payload

    def _json_task_request(self, task_type, subtask, *args, timeout=10):
        self.s.send(datahandler.format_socket_data(task_type, subtask, *args))
        return self._recv_json_task_response(timeout)

    def _json_raw_task_request(self, task_type, *args, timeout=10):
        self.s.send(datahandler.format_socket_data(task_type, *args))
        return self._recv_json_task_response(timeout)

    def _recv_json_task_response(self, timeout=10):
        chunks = []
        old_timeout = self.s.gettimeout()
        self.s.settimeout(timeout)
        try:
            while True:
                chunk = self.s.recv(65535)
                chunks.append(chunk)
                if chunk.endswith(b"\r\n"):
                    break
        finally:
            self.s.settimeout(old_timeout)
        result = datahandler.decode_socket_data(b"".join(chunks))
        if not result[0]:
            return result
        payload = result[1][0] if len(result[1]) else "{}"
        try:
            decoded_payload = base64.b64decode(payload).decode()
            return True, json.loads(decoded_payload)
        except Exception:
            return False, "Unable to decode JSON task response: " + payload

    def clear_all_photos(self):
        """Delete all assets from the iOS Photos library."""
        return self._json_task_request(tasktypes.TASK_PHOTOS, 1, timeout=60)

    def add_photo_from_file(self, image_path):
        """Add an image file already present on the iOS device to Photos."""
        return self._json_task_request(tasktypes.TASK_PHOTOS, 2, image_path, timeout=30)

    def add_photo_from_base64(self, image_base64, extension="jpg"):
        """Add an image to Photos from a base64 encoded buffer."""
        try:
            image_bytes = base64.b64decode(image_base64)
        except Exception:
            return False, "Image buffer is not valid base64."
        return self.add_photo_from_bytes(image_bytes, extension=extension)

    def add_photo_from_bytes(self, image_bytes, extension="jpg", chunk_size=1200):
        """Upload image bytes from the current Python process and add them to Photos."""
        if not image_bytes:
            return False, "Image buffer cannot be empty."

        upload_id = uuid.uuid4().hex
        success, result = self._json_task_request(tasktypes.TASK_PHOTOS, 4, upload_id, extension, timeout=10)
        if not success:
            return False, result

        for offset in range(0, len(image_bytes), chunk_size):
            chunk = image_bytes[offset:offset + chunk_size]
            chunk_payload = base64.b64encode(chunk).decode()
            success, result = self._json_task_request(tasktypes.TASK_PHOTOS, 5, upload_id, extension, chunk_payload, timeout=10)
            if not success:
                return False, result

        return self._json_task_request(tasktypes.TASK_PHOTOS, 6, upload_id, extension, timeout=30)

    def add_photo_from_pc_file(self, image_path, extension=None, chunk_size=1200):
        """Serve a local PC image over HTTP temporarily and import it into iOS Photos."""
        return self.add_photo_from_pc_file_http(image_path)

    def add_photo_from_url(self, image_url):
        """Download an image URL from the iOS device and add it to Photos."""
        return self._json_task_request(tasktypes.TASK_PHOTOS, 7, image_url, timeout=60)

    def add_photo_from_pc_file_http(self, image_path, host="0.0.0.0", port=0):
        """Import a PC image by hosting a temporary local HTTP server.

        This avoids sending image bytes through ZXTouch's line-based socket protocol.
        The iPhone must be able to reach the PC on the selected network address.
        """
        image_path = os.path.abspath(image_path)
        directory = os.path.dirname(image_path)
        file_name = os.path.basename(image_path)
        handler = functools.partial(http.server.SimpleHTTPRequestHandler, directory=directory)

        class ReusableTCPServer(socketserver.TCPServer):
            allow_reuse_address = True

        server = ReusableTCPServer((host, port), handler)
        server_port = server.server_address[1]
        thread = threading.Thread(target=server.serve_forever, daemon=True)
        thread.start()

        try:
            pc_host = self.s.getsockname()[0]
            image_url = "http://{}:{}/{}".format(pc_host, server_port, file_name)
            return self.add_photo_from_url(image_url)
        finally:
            server.shutdown()
            server.server_close()

    def capture_screen(self, save_path=""):
        """Capture the current iOS screen and save it on the device as a PNG file."""
        return self._json_task_request(tasktypes.TASK_SCREEN_CAPTURE, 1, save_path, timeout=30)

    def capture_screen_bytes(self):
        """Capture the current iOS screen and return PNG bytes to the current Python process."""
        success, result = self._json_task_request(tasktypes.TASK_SCREEN_CAPTURE, 2, timeout=60)
        if not success:
            return False, result
        try:
            return True, base64.b64decode(result.get("data", ""))
        except Exception:
            return False, "Unable to decode screenshot data."

    def capture_screen_to_pc_file(self, local_path):
        """Capture the current iOS screen and write the PNG file on the PC."""
        success, data = self.capture_screen_bytes()
        if not success:
            return False, data
        with open(local_path, "wb") as output_file:
            output_file.write(data)
        return True, {"path": local_path, "size": len(data), "format": "png"}

    def check_crane(self):
        """Check whether Crane/libCrane is available on the device."""
        return self._crane_request(1)

    def crane_supported_apps(self):
        """Return apps supported by Crane."""
        return self._crane_request(2)

    def crane_apps_with_containers(self):
        """Return apps that currently have non-default Crane containers."""
        return self._crane_request(3)

    def crane_get_containers(self, bundle_identifier):
        """Return Crane containers of an app."""
        return self._crane_request(4, bundle_identifier)

    def crane_get_active_container(self, bundle_identifier):
        """Return the active Crane container of an app."""
        return self._crane_request(5, bundle_identifier)

    def crane_set_active_container(self, bundle_identifier, container_identifier):
        """Set the active Crane container of an app."""
        return self._crane_request(6, bundle_identifier, container_identifier)

    def crane_create_container(self, bundle_identifier, container_name, container_identifier=""):
        """Create a new Crane container for an app."""
        return self._crane_request(7, bundle_identifier, container_name, container_identifier)

    def crane_delete_container(self, bundle_identifier, container_identifier):
        """Delete a Crane container from an app."""
        return self._crane_request(8, bundle_identifier, container_identifier)

    def crane_delete_container_content(self, bundle_identifier, container_identifier):
        """Delete the content of a Crane container without deleting the container."""
        return self._crane_request(9, bundle_identifier, container_identifier)

    def crane_wipe_container(self, bundle_identifier, container_identifier, repopulate=True):
        """Wipe a Crane container."""
        return self._crane_request(10, bundle_identifier, container_identifier, int(bool(repopulate)))

    def crane_make_default(self, bundle_identifier, container_identifier):
        """Make a Crane container the default container for an app."""
        return self._crane_request(11, bundle_identifier, container_identifier)

    def crane_get_container_settings(self, bundle_identifier, container_identifier):
        """Return Crane settings for a container."""
        return self._crane_request(12, bundle_identifier, container_identifier)

    def crane_set_container_settings(self, bundle_identifier, container_identifier, settings):
        """Replace Crane settings for a container with a dict."""
        settings_json = json.dumps(settings or {}, separators=(",", ":"))
        settings_payload = base64.b64encode(settings_json.encode()).decode()
        return self._crane_request(13, bundle_identifier, container_identifier, settings_payload)

    def crane_launch_app_with_container(self, bundle_identifier, container_identifier):
        """Set active Crane container, reload the app, and bring it to foreground."""
        return self._crane_request(14, bundle_identifier, container_identifier)

    def prompt_input(self, title="ZXTouch", message="", placeholder="", default_value=""):
        """Ask the user for text using a native alert.

        Returns:
            Result tuple: (success?, entered_text/error_message)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_PROMPT_INPUT, title, message, placeholder, default_value))
        result = datahandler.decode_socket_data(self.s.recv(2048))
        if not result[0]:
            return False, result[1]
        return True, result[1][0] if len(result[1]) else ""

    def start_touch_recording(self):
        """Start recording touch events

        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_TOUCH_RECORDING_START))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def stop_touch_recording(self):
        """Stop recording touch events

        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_TOUCH_RECORDING_STOP))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def accurate_usleep(self, microseconds):
        """Don't know why, but python on ios will not sleep accurately sometimes. So you can use this to sleep

        :param microseconds: microseconds to sleep
        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_USLEEP, microseconds))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def play_script(self, script_absolute_path):
        """Play a script

        :param script_absolute_path: the absolute path of the script
        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_PLAY_SCRIPT, script_absolute_path))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def force_stop_script_play(self):
        """Force stopping playing current script"""
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_PLAY_SCRIPT_FORCE_STOP))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def image_match(self, template_path, acceptable_value=0.8, max_try_times=2, scaleRation=0.8):
        """Get the coordinate of a image

        :param template_path: template path on your ios device
        :param acceptable_value: for a successful match, the acceptable value
        :param max_try_times: how many times you want to try with different size of the template
        :param scaleRation: for each time you try, what the template size should be

        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_TEMPLATE_MATCH, template_path, max_try_times,
                                                   acceptable_value, scaleRation))
        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return False, result[1]

        return True, {"x": result[1][0], "y": result[1][1], "width": result[1][2], "height": result[1][3]}

    def show_toast(self, toast_type, content, duration, position=0, fontSize=0):
        """Show toast on ios device

        :param type: type of the toast.
        :param content: content of the toast
        :param duration: duration of the toast
        :param position: position of the toast. 0 for top, 1 for bottom
        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_SHOW_TOAST, toast_type, content, duration, position,
                                                    fontSize))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def toast(self, type="info", message="", position="top", fontSize=0, timeout=2):
        """Show a toast with string based options."""
        toast_type = _TOAST_TYPE_MAP.get(str(type).lower(), _TOAST_TYPE_MAP["info"])
        toast_position = _TOAST_POSITION_MAP.get(str(position).lower(), _TOAST_POSITION_MAP["top"])
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_SHOW_TOAST, 91, toast_type, message, timeout,
                                                   toast_position, fontSize))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def toast_progress(self, message="", position="top", fontSize=0):
        """Show a persistent progress toast. Returns a ToastProgress handle."""
        toast_id = uuid.uuid4().hex
        toast_position = _TOAST_POSITION_MAP.get(str(position).lower(), _TOAST_POSITION_MAP["top"])
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_SHOW_TOAST, 92, toast_id, message, toast_position,
                                                   fontSize))
        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return result
        return True, ToastProgress(self, toast_id)

    def _toast_progress_update(self, toast_id, message):
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_SHOW_TOAST, 93, toast_id, message))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def _toast_progress_stop(self, toast_id):
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_SHOW_TOAST, 94, toast_id))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def pick_color(self, x, y):
        """Get the rgb value from the screen. The format returned is (red, green, blue)

        :param x: x coordinate of the point on the screen
        :param y: y coordinate of the point on the screen
        :return: Result tuple: (success?, error_message/dictionary that stores the result)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_COLOR_PICKER, x, y))
        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return False, result[1]

        return True, {"red": result[1][0], "green": result[1][1], "blue": result[1][2]}

    def search_color(self, region, red_min, red_max, green_min, green_max, blue_min, blue_max, pixel_to_skip = 0):
        """Search color from a region

        Args:
            region: a tuple containing start_x, start_y, width, height of the region to search. Format: (x, y, width, height)
            red_min: min value of the red color of the point to search.
            red_max: max value of the red color of the point to search.
            green_min: min value of the green color of the point to search.
            green_max: max value of the green color of the point to search.
            blue_min: min value of the blue color of the point to search.
            blue_max: max value of the blue color of the point to search.
            pixel_to_skip: how many pixel to skip when searching.
                            For example, if the value is 1, and the start point is (0,0). Then it will only search for (0, 0), (0, 2), (0, 4) .... (2, 0), (2, 2)
                            For example, if the value is 2, and the start point is (0,0). Then it will only search for (0, 0), (0, 3), (0, 5) .... (3, 0), (3, 2)

        Returns:
            Result tuple: (success?, error_message/return value)

            if the operation successes, the return value will be an array of texts in the region.
        """
        if len(region) != 4:
            raise RuntimeError("The format of the region should be (x, y, width, height)")
            return

        self.s.send(datahandler.format_socket_data(tasktypes.TASK_COLOR_SEARCHER, colorsearchtasktypes.SEARCH_RGB_SINGLE_POINT, region[0], region[1], region[2], region[3], red_min, red_max, green_min, green_max, blue_min, blue_max, pixel_to_skip))
        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return False, result[1]

        return True, {"x": result[1][0], "y": result[1][1], "red": result[1][2], "green": result[1][3], "blue": result[1][4]}



    def show_keyboard(self):
        """Show the keyboard

        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(
            datahandler.format_socket_data(tasktypes.TASK_KEYBOARDIMPL, kbdtasktypes.KEYBOARD_VIRTUAL_KEYBOARD, 2))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def hide_keyboard(self):
        """hide the keyboard

        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(
            datahandler.format_socket_data(tasktypes.TASK_KEYBOARDIMPL, kbdtasktypes.KEYBOARD_VIRTUAL_KEYBOARD, 1))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def paste_from_clipboard(self):
        """paste text from clip board

        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(
            datahandler.format_socket_data(tasktypes.TASK_KEYBOARDIMPL, kbdtasktypes.KEYBOARD_PASTE_FROM_CLIPBOARD))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def get_text_from_clipboard(self):
        """Get text from clip board

        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(
            datahandler.format_socket_data(tasktypes.TASK_KEYBOARDIMPL, kbdtasktypes.KEYBOARD_GET_TEXT_FROM_CLIPBOARD))
        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return False, result[1]
        return True, result[1][0]

    def set_clipboard_text(self, text):
        """Set clipboard text

        :param text: text to set
        :return: Result tuple: (success?, error_message/return value)
        """
        self.s.send(
            datahandler.format_socket_data(tasktypes.TASK_KEYBOARDIMPL, kbdtasktypes.KEYBOARD_SAVE_TEXT_TO_CLIPBOARD, text))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def insert_text(self, text):
        """Insert text into the text field

        :param text: text to insert
        :return:
        """
        for i, ch in enumerate(text):
            if ch == "\b":
                self.s.send(
                    datahandler.format_socket_data(tasktypes.TASK_KEYBOARDIMPL, kbdtasktypes.KEYBOARD_DELETE_CHARACTERS,
                                                   1))
                datahandler.decode_socket_data(self.s.recv(1024))
            else:
                self.s.send(
                    datahandler.format_socket_data(tasktypes.TASK_KEYBOARDIMPL, kbdtasktypes.KEYBOARD_INSERT_TEXT, ch))
                datahandler.decode_socket_data(self.s.recv(1024))
        return True, ""


    def move_cursor(self, offset):
        """Move the cursor on the text field

        :param offset: the related position you want to move. To move left, offset should be negative. For moving right, it should be positive.
        :return:
        """
        self.s.send(
            datahandler.format_socket_data(tasktypes.TASK_KEYBOARDIMPL, kbdtasktypes.KEYBOARD_MOVE_CURSOR, offset))
        return datahandler.decode_socket_data(self.s.recv(1024))

    def get_screen_size(self):
        """Get screen size in pixels

        :return: Result tuple: (success?, error_message/dictionary that stores the result)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_GET_DEVICE_INFO,
                                                   deviceinfotasktypes.DEVICE_INFO_TASK_GET_SCREEN_SIZE))
        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return False, result[1]
        return True, {"width": result[1][0], "height": result[1][1]}

    def get_screen_orientation(self):
        """Get orientation of the screen

        :return: Result tuple: (success?, error_message/screen orientation(str, can be convert to int))
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_GET_DEVICE_INFO,
                                                   deviceinfotasktypes.DEVICE_INFO_TASK_GET_SCREEN_ORIENTATION))
        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return False, result[1]
        return True, result[1][0]

    def get_screen_scale(self):
        """Get screen scale

        :return: Result tuple: (success?, error_message/screen scale(str, can be convert to int))
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_GET_DEVICE_INFO,
                                                   deviceinfotasktypes.DEVICE_INFO_TASK_GET_SCREEN_SCALE))
        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return False, result[1]
        return True, result[1][0]

    def get_device_info(self):
        """Get information of the device

        :return: Result tuple: (success?, error_message/dictionary that stores device information)
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_GET_DEVICE_INFO,
                                                   deviceinfotasktypes.DEVICE_INFO_TASK_GET_DEVICE_INFO))
        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return False, result[1]
        return True, {"name": result[1][0], "system_name": result[1][1], "system_version": result[1][2],
                      "model": result[1][3], "identifier_for_vendor": result[1][4]}

    def get_device_details(self):
        """Get extended device information as a dictionary.

        Some identifiers such as IMEI, serial number, UDID, Wi-Fi/Bluetooth address
        are best-effort and can be None when iOS or entitlements block access.
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_GET_DEVICE_INFO,
                                                   deviceinfotasktypes.DEVICE_INFO_TASK_GET_DEVICE_DETAILS))
        result = datahandler.decode_socket_data(self.s.recv(8192))
        if not result[0]:
            return False, result[1]
        payload = result[1][0] if len(result[1]) else "{}"
        try:
            return True, json.loads(payload)
        except Exception:
            return False, "Unable to decode device details response: " + payload

    def get_battery_info(self):
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_GET_DEVICE_INFO,
                                                   deviceinfotasktypes.DEVICE_INFO_TASK_GET_BATTERY_INFO))
        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return False, result[1]
        battery_state_return = int(result[1][0])
        battery_state_list = ["Unknown", "Unplugged", "Charging", "Full"]

        return True, {"battery_state": result[1][0], "battery_level": str(int(float(result[1][1]))),
                      "battery_state_string": battery_state_list[battery_state_return]}  # state: 0 unknown, 1 unplegged, 2 charging, 3 full

    def ocr(self, region, custom_words=[], minimum_height="", recognition_level=0, languages=[], auto_correct=0, debug_image_path=""):
        """Get text from a region

        Args:
            region: a tuple containing start_x, start_y, width, height of the region to ocr. Format: (x, y, width, height)
            custom_words: an array of strings to supplement the recognized languages at the word recognition stage.
            minimum_height: the minimum height of the text expected to be recognized, relative to the image height. The default value is 1/32
            recognition_level: a value that determines whether the request prioritizes accuracy or speed in text recognition. 0 means accurate. 1 means faster.
            languages: an array of languages to detect, in priority order.  Default: english. Use get_supported_ocr_languages() to get the language list.
            auto_correct: whether ocr engine applies language correction during the recognition process. 0 means no, 1 means yes
            debug_image_path: debug image path. If you DONT want the ocr engine to output the debug image, leave it blank

        Returns:
            Result tuple: (success?, error_message/return value)

            if the operation successes, the return value will be an array of texts in the region.
        """
        if len(region) != 4:
            raise RuntimeError("The format of the region should be (x, y, width, height)")
            return

        rect_data = ",,".join(map(str, region))
        custom_words_data = ",,".join(map(str, custom_words))
        languages_data = ",,".join(map(str, languages))

        self.s.send(datahandler.format_socket_data(tasktypes.TASK_TEXT_RECOGNIZER,
                                                   1, rect_data, custom_words_data, minimum_height, recognition_level,
                                                   languages_data, auto_correct, debug_image_path))

        result = datahandler.decode_socket_data(self.s.recv(2048))
        if not result[0]:
            return False, result[1]

        string_info_list = []
        raw_info_list = result[1]
        for raw_info in raw_info_list:
            if not raw_info:
                continue
            single_string_info = raw_info.split(",,")
            temp_dict = {"text": single_string_info[0], "x": single_string_info[1], "y": single_string_info[2],
                         "width": single_string_info[3], "height": single_string_info[4]}
            string_info_list.append(temp_dict)

        return True, string_info_list

    def tap_text(self, text, region=None, exact=False, case_sensitive=False, ignore_accents=False, occurrence=0,
                 custom_words=[], minimum_height="", recognition_level=0, languages=[], auto_correct=0,
                 debug_image_path="", finger_index=1, tap_duration=0.05):
        """Find text with OCR and tap the center of the matched text box.

        Args:
            text: text to search for. By default this can be a substring, so
                  "Google" matches OCR result "Login with Google".
            region: OCR region as (x, y, width, height). None means full screen.
            exact: True requires the OCR text to equal text.
            case_sensitive: True keeps case while matching.
            ignore_accents: True ignores Vietnamese/Latin accents while matching.
            occurrence: zero-based matched result index to tap when multiple items match.
            custom_words/minimum_height/recognition_level/languages/auto_correct/debug_image_path:
                forwarded to ocr().
            finger_index: finger index used for the tap.
            tap_duration: seconds between TOUCH_DOWN and TOUCH_UP.

        Returns:
            Result tuple. On success, result[1] is a dict with tap coordinates and OCR box.
        """
        if not text:
            return False, "Text to tap cannot be empty."

        if region is None:
            success, screen_size = self.get_screen_size()
            if not success:
                return False, screen_size
            region = (0, 0, int(float(screen_size["width"])), int(float(screen_size["height"])))

        success, results = self.ocr(region, custom_words=custom_words, minimum_height=minimum_height,
                                    recognition_level=recognition_level, languages=languages,
                                    auto_correct=auto_correct, debug_image_path=debug_image_path)
        if not success:
            return False, results

        target = _normalize_text_for_match(text, case_sensitive=case_sensitive, ignore_accents=ignore_accents)
        matched_count = 0

        for item in results:
            candidate = item.get("text", "")
            candidate_to_match = _normalize_text_for_match(candidate, case_sensitive=case_sensitive,
                                                           ignore_accents=ignore_accents)
            matched = candidate_to_match == target if exact else target in candidate_to_match
            if not matched:
                continue

            if matched_count != occurrence:
                matched_count += 1
                continue

            x = float(item["x"])
            y = float(item["y"])
            width = float(item["width"])
            height = float(item["height"])
            tap_x = x + width / 2
            tap_y = y + height / 2

            self.touch(touchtypes.TOUCH_DOWN, finger_index, tap_x, tap_y)
            time.sleep(tap_duration)
            self.touch(touchtypes.TOUCH_UP, finger_index, tap_x, tap_y)

            return True, {"text": candidate, "x": tap_x, "y": tap_y, "box": item}

        return False, "Text not found: " + str(text)

    def wait_for_text(self, text, timeout=10, interval=0.5, region=None, exact=False, case_sensitive=False,
                      ignore_accents=False, occurrence=0, custom_words=[], minimum_height="", recognition_level=0,
                      languages=[], auto_correct=0, debug_image_path=""):
        """Wait until OCR finds text or timeout expires.

        Args:
            text: text to search for. By default this can be a substring, so
                  "Google" matches OCR result "Login with Google".
            timeout: maximum seconds to wait. 0 means check once.
            interval: seconds between OCR attempts.
            region: OCR region as (x, y, width, height). None means full screen.
            exact: True requires the OCR text to equal text.
            case_sensitive: True keeps case while matching.
            ignore_accents: True ignores Vietnamese/Latin accents while matching.
            occurrence: zero-based matched result index to return when multiple items match.
            custom_words/minimum_height/recognition_level/languages/auto_correct/debug_image_path:
                forwarded to ocr().

        Returns:
            Result tuple. On success, result[1] is a dict with OCR box and elapsed seconds.
        """
        if not text:
            return False, "Text to wait for cannot be empty."

        if region is None:
            success, screen_size = self.get_screen_size()
            if not success:
                return False, screen_size
            region = (0, 0, int(float(screen_size["width"])), int(float(screen_size["height"])))

        timeout = max(0, float(timeout))
        interval = max(0.05, float(interval))
        start_time = time.time()
        deadline = start_time + timeout
        target = _normalize_text_for_match(text, case_sensitive=case_sensitive, ignore_accents=ignore_accents)

        while True:
            success, results = self.ocr(region, custom_words=custom_words, minimum_height=minimum_height,
                                        recognition_level=recognition_level, languages=languages,
                                        auto_correct=auto_correct, debug_image_path=debug_image_path)
            if not success:
                return False, results

            matched_count = 0
            for item in results:
                candidate = item.get("text", "")
                candidate_to_match = _normalize_text_for_match(candidate, case_sensitive=case_sensitive,
                                                               ignore_accents=ignore_accents)
                matched = candidate_to_match == target if exact else target in candidate_to_match
                if not matched:
                    continue

                if matched_count != occurrence:
                    matched_count += 1
                    continue

                item["elapsed"] = time.time() - start_time
                return True, item

            if time.time() >= deadline:
                return False, "Timeout waiting for text: " + str(text)

            time.sleep(min(interval, max(0.05, deadline - time.time())))

    def get_supported_ocr_languages(self, recognition_level):
        """Get languages that can be recognized by ocr

        Args:
            recognition_level: a value that determines whether the request prioritizes accuracy or speed in text recognition. 0 means accurate. 1 means faster.

        Returns:
            Result tuple: (success?, error_message/return value)

            if the operation successes, the return value will be an array of available languages .
        """
        self.s.send(datahandler.format_socket_data(tasktypes.TASK_TEXT_RECOGNIZER,
                                                   2, recognition_level))

        result = datahandler.decode_socket_data(self.s.recv(1024))
        if not result[0]:
            return False, result[1]

        return True, result[1]

    def disconnect(self):
        self.s.close()
